// ICONIK CREDENTIALS — configured 2026-06-08
const ICONIK_APP_ID     = '***REMOVED***';
const ICONIK_AUTH_TOKEN = '***REMOVED***';

const inp = $input.first().json;
return [{json:{
  target_course_id:    inp.target_course_id,
  iconik_app_id:       ICONIK_APP_ID,
  iconik_auth_token:   ICONIK_AUTH_TOKEN,
  root_collection_name:'0000_LOCALISATION'
}}];

const a = $('Build Auth').first().json;
const APP = a.iconik_app_id, TOK = a.iconik_auth_token;
const tid = String(a.target_course_id || '').trim();
const base = 'https://app.iconik.io';
const H = { 'App-ID': APP, 'Auth-Token': TOK, 'Content-Type': 'application/json' };
const http = this.helpers.httpRequest;

const searchColl = async (title) => {
  const r = await http({ method:'POST', url: base+'/API/search/v1/search/', headers:H, body:{ doc_types:['collections'], query:title, per_page:50 }, json:true });
  return (r.objects||[]).filter(o => (o.title||'').trim() === title);
};
const childColls = async (pid) => {
  const r = await http({ method:'GET', url: base+`/API/assets/v1/collections/${pid}/contents/?object_types=collections&per_page=200`, headers:H, json:true });
  return r.objects||[];
};
const createColl = async (title, parent_id) => {
  const body = { title };
  if (parent_id) body.parent_id = parent_id;
  const r = await http({ method:'POST', url: base+'/API/assets/v1/collections/', headers:H, body, json:true });
  return r.id;
};
const ensureRoot = async (title) => {
  const hits = await searchColl(title);
  const top = hits.find(o => !o.parent_id) || hits[0];
  return top ? top.id : await createColl(title, null);
};
const ensureUnder = async (parent_id, title) => {
  const kids = await childColls(parent_id);
  const hit = kids.find(o => (o.title||'').trim() === title);
  return hit ? hit.id : await createColl(title, parent_id);
};

const root = await ensureRoot('0000_LOCALISATION');
const target = await ensureUnder(root, tid);
const graphics = await ensureUnder(target, 'static_graphics');
const files = await ensureUnder(target, 'external_files');
const transcripts = await ensureUnder(target, 'transcripts');
const pdf = await ensureUnder(target, 'pdf_to_be_localized');

return [{ json: {
  target_course_id: tid,
  root_collection_id: root,
  target_collection_id: target,
  graphics_collection_id: graphics,
  files_collection_id: files,
  transcripts_collection_id: transcripts,
  pdf_collection_id: pdf,
  iconik_ready: !!(root && target && graphics)
}}];

